// ParseLLM & Merge
// LLM Chain devuelve solo { text: '...' }
// Datos del partido se recuperan desde Loop Over Items (fuente confiable)
return items.map(item => {

  // ── 1. Parsear respuesta LLM ──────────────────────────────
  const rawText = item.json?.text || '';
  let parsed = null;

  if (rawText) {
    let clean = rawText.trim()
      .replace(/```json\s*/gi, '')
      .replace(/```\s*/g, '')
      .trim();
    try {
      parsed = JSON.parse(clean);
    } catch (e) {
      try {
        const m = clean.match(/\{[\s\S]*\}/);
        parsed = m ? JSON.parse(m[0]) : null;
      } catch (e2) { parsed = null; }
    }
  }

  const llm = {
    tipo:       parsed?.tipo       || 'ninguno',
    riesgo:     parsed?.riesgo     || 'alto',
    confianza:  Number(parsed?.confianza ?? 0),
    comentario: parsed?.comentario || 'Sin análisis'
  };

  // ── 2. Datos del partido desde Loop Over Items ─────────────
  const src = $('Loop Over Items').item.json;

  return {
    json: {
      match:          src.match          ?? null,
      best:           src.best           ?? null,
      league:         src.league         ?? null,
      country:        src.country        ?? null,
      region:         src.region         ?? null,
      horasRestantes: src.horasRestantes ?? null,
      surebet:        src.surebet        ?? false,
      beneficioPct:   src.beneficioPct   ?? 0,
      margen:         src.margen         ?? null,
      stakes:         src.stakes         ?? null,
      capitalTotal:   src.capitalTotal   ?? 100,
      currencies:     src.currencies     ?? { home: 'PEN', draw: 'PEN', away: 'PEN' },
      tipo:       llm.tipo,
      riesgo:     llm.riesgo,
      confianza:  llm.confianza,
      comentario: llm.comentario
    }
  };
});

// ValueCalc — Opción A
// Probabilidades implícitas derivadas matemáticamente de las cuotas
// NO se usan probabilidades del LLM
const threshold = Number($('CONFIG').first().json.CFG_VALUE_THRESHOLD ?? 1.05);

return items.map(item => {
  const { match, best, stakes, beneficioPct, capitalTotal, currencies, surebet,
          tipo, riesgo, confianza, comentario, league, country, region,
          horasRestantes, margen } = item.json;

  // Probabilidades implícitas normalizadas (eliminan el margen de la casa)
  const oHome = best?.home?.odds || 0;
  const oDraw = best?.draw?.odds || 0;
  const oAway = best?.away?.odds || 0;

  const invSum = (oHome > 0 ? 1/oHome : 0)
               + (oDraw > 0 ? 1/oDraw : 0)
               + (oAway > 0 ? 1/oAway : 0);

  const prob = invSum > 0 ? {
    local:     (1/oHome) / invSum,
    empate:    (1/oDraw) / invSum,
    visitante: (1/oAway) / invSum
  } : { local: 0.33, empate: 0.33, visitante: 0.34 };

  // Valor esperado por resultado
  const valHome = prob.local     * oHome;
  const valDraw = prob.empate    * oDraw;
  const valAway = prob.visitante * oAway;

  const valueBets = [];
  if (valHome > threshold) valueBets.push({
    outcome: 'home', label: 'Local',
    valor: valHome,
    roi: ((valHome - 1) * 100).toFixed(2),
    bookmaker: best?.home?.bookmaker,
    cuota: best?.home?.odds
  });
  if (valDraw > threshold) valueBets.push({
    outcome: 'draw', label: 'Empate',
    valor: valDraw,
    roi: ((valDraw - 1) * 100).toFixed(2),
    bookmaker: best?.draw?.bookmaker,
    cuota: best?.draw?.odds
  });
  if (valAway > threshold) valueBets.push({
    outcome: 'away', label: 'Visitante',
    valor: valAway,
    roi: ((valAway - 1) * 100).toFixed(2),
    bookmaker: best?.away?.bookmaker,
    cuota: best?.away?.odds
  });

  return {
    json: {
      match, best, league, country, region, horasRestantes, margen,
      prob, valueBets, surebet,
      tipo, riesgo, confianza, comentario,
      stakes, capitalTotal, currencies,
      beneficioPct,
      roiPct: valueBets.map(v => v.roi)
    }
  };
});

// Formatear todos los campos para presentación
return items.map(item => {
  const out = { ...item.json };

  // Beneficio formateado
  out.beneficioPctFmt = out.beneficioPct !== undefined
    ? `${Number(out.beneficioPct).toFixed(2)}%`
    : '0.00%';

  // Stakes formateados con moneda correcta
  if (out.stakes && out.currencies) {
    out.stakesRounded = {
      home: Number(out.stakes.home).toFixed(2),
      draw: Number(out.stakes.draw).toFixed(2),
      away: Number(out.stakes.away).toFixed(2)
    };
  } else {
    out.stakesRounded = { home: '0.00', draw: '0.00', away: '0.00' };
  }

  // Cuotas formateadas
  if (out.best) {
    out.bestFmt = {
      home: `${out.best.home?.odds ?? '-'} (${out.best.home?.bookmaker ?? '-'})`,
      draw: `${out.best.draw?.odds ?? '-'} (${out.best.draw?.bookmaker ?? '-'})`,
      away: `${out.best.away?.odds ?? '-'} (${out.best.away?.bookmaker ?? '-'})`
    };
  }

  // Etiqueta de tipo para el mensaje
  const tipoLabel = out.tipo === 'surebet' ? '🔒 Surebet'
    : out.tipo === 'valuebet' ? '📈 Value Bet'
    : '⚪ Sin oportunidad';
  out.tipoLabel = tipoLabel;

  // Liga y país formateados
  out.ligaFmt = [out.league, out.country].filter(Boolean).join(' · ') || 'Liga desconocida';

  // Value bets summary
  out.valueBetsFmt = (out.valueBets || []).length > 0
    ? out.valueBets.map(v => `${v.label}: cuota ${v.cuota} en ${v.bookmaker} (ROI +${v.roi}%)`).join('\n')
    : null;

  return { json: out };
});

// Filtrar partidos por ventana de tiempo
// timestamp en el scraper = Unix seconds (entero)
const cfg = $('CONFIG').first().json;
const maxHoras = cfg.CFG_MAX_HORAS_AL_PARTIDO ?? 48;

return items.filter(item => {
  const ts = item.json.timestamp;
  if (ts === null || ts === undefined) return true;

  // Unix timestamp en segundos → multiplicar por 1000 para ms
  const matchTime = Number(ts) * 1000;
  const now = Date.now();

  // Descartar partidos ya iniciados
  if (matchTime <= now) return false;

  const horasRestantes = (matchTime - now) / (1000 * 60 * 60);
  return horasRestantes <= maxHoras;
}).map(item => ({
  json: {
    ...item.json,
    horasRestantes: parseFloat(
      ((Number(item.json.timestamp) * 1000 - Date.now()) / (1000 * 60 * 60)).toFixed(1)
    )
  }
}));

// Análisis estadístico de casas de apuestas
// Solo analiza las ligas configuradas en CFG_LEAGUES
const cfg = $('CONFIG').first().json;

let allowedLeagues = [];
try {
  allowedLeagues = JSON.parse(cfg.CFG_LEAGUES || '[]');
} catch(e) {
  allowedLeagues = (cfg.CFG_LEAGUES || '')
    .split(',')
    .map(l => l.trim())
    .filter(Boolean);
}

const normalize = str => str
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

const allowedNorm = allowedLeagues.map(normalize);

const raw = items[0].json;
const allEvents = raw.events || [];

const events = allowedNorm.length === 0
  ? allEvents
  : allEvents.filter(e => {
      const league = normalize(e.league || e.league_raw || '');
      return allowedNorm.some(a => league.includes(a) || a.includes(league));
    });

const ranking = {};
let totalPartidos = 0;

events.forEach(e => {
  const bookmakers = e.canonical?.bookmakers || {};
  const bkList = Object.keys(bookmakers);
  if (bkList.length === 0) return;

  totalPartidos++;

  let bestHome = { bk: null, odds: -1 };
  let bestDraw = { bk: null, odds: -1 };
  let bestAway = { bk: null, odds: -1 };

  bkList.forEach(bk => {
    const odds = bookmakers[bk].odds || {};
    const ox = odds['1X2'] || odds['1x2'] || null;
    if (!ox) return;

    if (!ranking[bk]) ranking[bk] = { home: 0, draw: 0, away: 0, total: 0, partidos: 0 };
    ranking[bk].partidos++;

    if (ox[0] > bestHome.odds) bestHome = { bk, odds: ox[0] };
    if (ox[1] > bestDraw.odds) bestDraw = { bk, odds: ox[1] };
    if (ox[2] > bestAway.odds) bestAway = { bk, odds: ox[2] };
  });

  if (bestHome.bk) { ranking[bestHome.bk].home++; ranking[bestHome.bk].total++; }
  if (bestDraw.bk) { ranking[bestDraw.bk].draw++; ranking[bestDraw.bk].total++; }
  if (bestAway.bk) { ranking[bestAway.bk].away++; ranking[bestAway.bk].total++; }
});

const sorted = Object.entries(ranking)
  .map(([bk, s]) => ({
    bookmaker: bk,
    total: s.total,
    home: s.home,
    draw: s.draw,
    away: s.away,
    partidos: s.partidos,
    pctMejorCuota: totalPartidos > 0
      ? ((s.total / (totalPartidos * 3)) * 100).toFixed(1)
      : '0.0'
  }))
  .sort((a, b) => b.total - a.total);

const top10 = sorted.slice(0, 10);
const fecha = new Date().toLocaleDateString('es-PE', {
  timeZone: 'America/Lima',
  day: '2-digit', month: '2-digit', year: 'numeric'
});

const ligasAnalizadas = [...new Set(events.map(e => e.league))].join(', ');

let msg = `🏆 Ranking de Casas — ${fecha}\n`;
msg += `📊 ${totalPartidos} partidos | Ligas: ${ligasAnalizadas}\n\n`;

top10.forEach((c, i) => {
  const medal = i === 0 ? '🥇' : i === 1 ? '🥈' : i === 2 ? '🥉' : `${i+1}.`;
  msg += `${medal} ${c.bookmaker} — mejor cuota ${c.pctMejorCuota}% del tiempo\n`;
  msg += `   🏠${c.home} 🤝${c.draw} ✈️${c.away}\n`;
});

msg += `\n💡 Abrir cuenta primero en:\n`;
msg += top10.slice(0, 3).map((c, i) => `  ${i+1}. ${c.bookmaker}`).join('\n');

return [{ json: { rankingMsg: msg, ranking: sorted, totalPartidos, ligasAnalizadas } }];

// Filtrar eventos por liga configurable
// CFG_LEAGUES es un string JSON con array de ligas permitidas
const cfg = $('CONFIG').first().json;

let allowedLeagues = [];
try {
  allowedLeagues = JSON.parse(cfg.CFG_LEAGUES || '[]');
} catch(e) {
  // Si no es JSON válido, intentar como lista separada por comas
  allowedLeagues = (cfg.CFG_LEAGUES || '')
    .split(',')
    .map(l => l.trim())
    .filter(Boolean);
}

// Si la lista está vacía, dejar pasar todo (sin filtro)
if (allowedLeagues.length === 0) {
  return items;
}

// Normalizar para comparación case-insensitive y sin acentos
const normalize = str => str
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .trim();

const allowedNorm = allowedLeagues.map(normalize);

const raw = items[0].json;
const events = raw.events || [];

const filtered = events.filter(e => {
  const league = e.league || e.league_raw || '';
  const leagueNorm = normalize(league);

  // Coincidencia exacta o parcial (ej: 'Copa Lib' matchea 'Copa Libertadores')
  return allowedNorm.some(allowed =>
    leagueNorm.includes(allowed) || allowed.includes(leagueNorm)
  );
});

// Log para debug en n8n
const skipped = events.length - filtered.length;
console.log(`Filter - ByLeague: ${filtered.length} eventos OK, ${skipped} descartados`);
console.log('Ligas permitidas:', allowedLeagues);
console.log('Ligas encontradas:', [...new Set(events.map(e => e.league))]);

if (filtered.length === 0) {
  // Retornar item vacío para no romper el flujo
  return [{ json: { events: [], _filteredCount: 0, _totalCount: events.length } }];
}

return [{ json: { ...raw, events: filtered, _filteredCount: filtered.length, _totalCount: events.length } }];

// ValidateLLM — detecta contradicciones entre análisis LLM y matemática
return items.map(item => {
  const d = item.json;
  const errors = [];
  const warnings = [];

  const margen       = d.margen       ?? null;
  const beneficioPct = d.beneficioPct ?? 0;
  const tipo         = d.tipo         || 'ninguno';
  const riesgo       = d.riesgo       || 'alto';
  const confianza    = d.confianza    ?? 0;
  const best         = d.best         || {};

  // ── Errores matemáticos graves ───────────────────────────

  // 1. LLM dice surebet pero margen >= 1
  if (tipo === 'surebet' && margen !== null && margen >= 1) {
    errors.push(`MATH_ERROR: tipo='surebet' pero margen=${margen.toFixed(4)} (debe ser < 1)`);
  }

  // 2. LLM dice ninguno pero margen < 1 (hay surebet real que el LLM ignoró)
  if (tipo === 'ninguno' && margen !== null && margen < 1) {
    errors.push(`MISSED_SUREBET: margen=${margen.toFixed(4)} < 1 pero LLM clasificó como 'ninguno'`);
  }

  // 3. Confianza 0 con datos completos (LLM usó el fallback mal)
  const hasOdds = best?.home?.odds && best?.draw?.odds && best?.away?.odds;
  if (confianza === 0 && hasOdds) {
    errors.push(`FALLBACK_ERROR: confianza=0 pero datos completos (match='${d.match}')`);
  }

  // 4. LLM dice riesgo='bajo' pero beneficioPct < 0.5
  if (riesgo === 'bajo' && beneficioPct < 0.5) {
    errors.push(`RISK_ERROR: riesgo='bajo' pero beneficioPct=${beneficioPct.toFixed(3)}% (debe ser > 2%)`);
  }

  // 5. LLM dice riesgo='bajo' pero tipo='ninguno'
  if (riesgo === 'bajo' && tipo === 'ninguno') {
    errors.push(`RISK_ERROR: riesgo='bajo' con tipo='ninguno' — imposible`);
  }

  // ── Warnings — inconsistencias menores ───────────────────

  // 6. Surebet con confianza < 40 (debería ser al menos 40)
  if (tipo === 'surebet' && confianza < 40) {
    warnings.push(`LOW_CONFIDENCE: surebet real pero confianza=${confianza}`);
  }

  // 7. Confianza > 80 con tipo='ninguno'
  if (tipo === 'ninguno' && confianza > 80) {
    warnings.push(`HIGH_CONFIDENCE_NINGUNO: confianza=${confianza} con tipo='ninguno'`);
  }

  // 8. beneficioPct > 0 pero tipo != 'surebet'
  if (beneficioPct > 0 && tipo !== 'surebet') {
    warnings.push(`TYPE_MISMATCH: beneficioPct=${beneficioPct.toFixed(3)}% > 0 pero tipo='${tipo}'`);
  }

  // ── Resultado ─────────────────────────────────────────────
  const llmValid  = errors.length === 0;
  const llmScore  = llmValid ? (warnings.length === 0 ? 'OK' : 'WARNING') : 'ERROR';

  // Si hay error grave: corregir tipo y confianza automáticamente
  let tipoFinal      = tipo;
  let confianzaFinal = confianza;
  let comentarioFinal = d.comentario || '';

  if (!llmValid) {
    // Corrección automática basada en matemática
    if (margen !== null && margen < 1) {
      tipoFinal      = 'surebet';
      confianzaFinal = beneficioPct > 1.5 ? 85 : beneficioPct > 0.5 ? 65 : 45;
      comentarioFinal = `[Auto-corregido] Surebet real: margen=${margen.toFixed(4)}, beneficio=${beneficioPct.toFixed(2)}%`;
    } else if (confianza === 0 && hasOdds) {
      // Fallback mal usado — asignar confianza mínima
      confianzaFinal = 10;
      comentarioFinal = `[Auto-corregido] Datos completos, sin oportunidad clara`;
    }
  }

  return {
    json: {
      ...d,
      // Valores corregidos
      tipo:       tipoFinal,
      confianza:  confianzaFinal,
      comentario: comentarioFinal,
      // Metadata de validación
      llmValid,
      llmScore,
      llmErrors:   errors,
      llmWarnings: warnings
    }
  };
});
